  { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
  { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
  { id: 'important', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
  { id: 'lab', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#EF4444' },
  { id: 'assignment', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' }
];

const MATERIAL_TYPE_MAP = MATERIAL_TYPES.reduce((map, type) => {
  map[type.id] = type;
  return map;
}, {});

// File Icons
const FILE_ICONS = {
  pdf: { icon: <FaFilePdf />, color: '#ef4444', label: 'PDF' },
  doc: { icon: <FaFileWord />, color: '#2563eb', label: 'DOC' },
  docx: { icon: <FaFileWord />, color: '#2563eb', label: 'DOCX' },
  ppt: { icon: <FaFilePowerpoint />, color: '#f97316', label: 'PPT' },
  pptx: { icon: <FaFilePowerpoint />, color: '#f97316', label: 'PPTX' },
  txt: { icon: <FaFileAlt />, color: '#6b7280', label: 'TEXT' },
  jpg: { icon: <FaFilePdf />, color: '#8b5cf6', label: 'JPG' },
  png: { icon: <FaFilePdf />, color: '#8b5cf6', label: 'PNG' },
  default: { icon: <FaFileAlt />, color: '#6b7280', label: 'FILE' }
};

const getFileIcon = (fileType) => {
  if (!fileType) return FILE_ICONS.default;
  const type = fileType.toLowerCase();
  return FILE_ICONS[type] || FILE_ICONS.default;
};

// Notification System
const showNotification = (title, message, type = 'success') => {
  const notification = document.createElement('div');
  const icon = type === 'success' ? '✅' : type === 'error' ? '❌' : '⚠️';
  const bgColor = type === 'success' 
    ? 'linear-gradient(135deg, #10b981, #34d399)' 
    : 'linear-gradient(135deg, #ef4444, #f87171)';
  
  notification.innerHTML = `
    <div style="
      position: fixed;
      top: 20px;
      right: 20px;
      background: ${bgColor};
      color: white;
      padding: 16px 20px;
      border-radius: 12px;
      box-shadow: 0 10px 25px rgba(0,0,0,0.2);
      z-index: 9999;
      display: flex;
      align-items: center;
      gap: 12px;
      animation: slideIn 0.3s ease;
      max-width: 350px;
      font-family: 'Segoe UI', sans-serif;
    ">
      <div style="font-size: 20px;">${icon}</div>
      <div>
        <div style="font-weight: 700; font-size: 15px;">${title}</div>
        <div style="font-size: 13px; opacity: 0.95;">${message}</div>
      </div>
    </div>
  `;
  
  document.body.appendChild(notification);
  
  // Add animation style
  if (!document.querySelector('#notification-styles')) {
    const style = document.createElement('style');
    style.id = 'notification-styles';
    style.textContent = `
      @keyframes slideIn {
        from { transform: translateX(100%); opacity: 0; }
        to { transform: translateX(0); opacity: 1; }
      }
      @keyframes slideOut {
        from { transform: translateX(0); opacity: 1; }
        to { transform: translateX(100%); opacity: 0; }
      }
    `;
    document.head.appendChild(style);
  }
  
  setTimeout(() => {
    notification.style.animation = 'slideOut 0.3s ease';
    setTimeout(() => notification.remove(), 300);
  }, 3000);
  
  return notification;
};

// FileTypeBadge Component
const FileTypeBadge = ({ fileType }) => {
  const iconData = getFileIcon(fileType);
  
  return (
    <span style={{
      background: `${iconData.color}20`,
      color: iconData.color,
      padding: '4px 10px',
      borderRadius: '20px',
      fontSize: '11px',
      fontWeight: 'bold',
      display: 'inline-flex',
      alignItems: 'center',
      gap: '5px'
    }}>
      {iconData.icon}
      {iconData.label}
    </span>
  );
};

// PreviewModal Component
const PreviewModal = ({ material, onClose, onDownload }) => {
  const fileIcon = getFileIcon(material.fileType);
  
  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      background: 'rgba(0,0,0,0.5)',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      zIndex: 1000,
      backdropFilter: 'blur(5px)'
    }}>
      <div style={{
        background: 'white',
        borderRadius: '16px',
        padding: '25px',
        maxWidth: '600px',
        width: '90%',
        maxHeight: '80vh',
        overflowY: 'auto',
        boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h3 style={{ color: '#1f2937', fontSize: '22px', fontWeight: '600', margin: 0 }}>
            {material.title}
          </h3>
          <button 
            onClick={onClose}
