          >
            ×
          </button>
        </div>
        
        <div style={{ background: '#f9fafb', padding: '20px', borderRadius: '12px', marginBottom: '20px' }}>
          <p style={{ color: '#4b5563', marginBottom: '15px', fontSize: '15px' }}>
            {material.description}
          </p>
          
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '15px' }}>
            <div style={{ background: 'white', padding: '12px', borderRadius: '8px' }}>
              <div style={{ fontSize: '12px', color: '#9ca3af', marginBottom: '5px' }}>📁 File Type</div>
              <div style={{ fontWeight: '600', color: '#374151' }}>{(material.fileType || 'PDF').toUpperCase()}</div>
            </div>
            <div style={{ background: 'white', padding: '12px', borderRadius: '8px' }}>
              <div style={{ fontSize: '12px', color: '#9ca3af', marginBottom: '5px' }}>📏 File Size</div>
              <div style={{ fontWeight: '600', color: '#374151' }}>{material.fileSize || 'N/A'}</div>
            </div>
            <div style={{ background: 'white', padding: '12px', borderRadius: '8px' }}>
              <div style={{ fontSize: '12px', color: '#9ca3af', marginBottom: '5px' }}>👤 Uploaded by</div>
