            </div>
            <div style={{ background: 'white', padding: '12px', borderRadius: '8px' }}>
              <div style={{ fontSize: '12px', color: '#9ca3af', marginBottom: '5px' }}>📅 Upload Date</div>
              <div style={{ fontWeight: '600', color: '#374151' }}>{material.uploadDate || 'N/A'}</div>
            </div>
          </div>
        </div>
        
        <div style={{ display: 'flex', gap: '12px', marginTop: '25px' }}>
          <button 
            onClick={() => {
              onClose();
              onDownload(material);
            }}
            style={{ 
              flex: '1', 
              padding: '14px', 
              background: 'linear-gradient(135deg, #10b981, #34d399)', 
              color: 'white', 
              border: 'none', 
              borderRadius: '10px', 
              cursor: 'pointer', 
              fontWeight: '600', 
              fontSize: '15px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            <FaDownload size={16} /> Download Now
          </button>
          <button 
            onClick={onClose}
            style={{ 
              flex: '1', 
              padding: '14px', 
              background: 'white', 
              color: '#374151', 
              border: '2px solid #e5e7eb', 
              borderRadius: '10px', 
              cursor: 'pointer', 
              fontWeight: '600', 
              fontSize: '15px' 
            }}
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
};

