        type: 'pyq',
        description: 'Previous year question papers with solutions and explanations',
        fileSize: '3.2 MB',
        pages: 35,
        uploadDate: '05 Jan 2024',
        downloads: 890,
        views: 2100,
        rating: 4.7,
        fileType: 'pdf',
        user: 'Exam Cell',
        isVerified: true
      },
      {
        id: 4,
        title: 'Important Questions',
        type: 'important',
        description: 'Most expected questions and important topics for exams',
        fileSize: '1.5 MB',
        pages: 18,
        uploadDate: '22 Jan 2024',
        downloads: 320,
        views: 780,
        rating: 4.6,
        fileType: 'pdf',
        user: 'Faculty'
      },
      {
        id: 5,
        title: 'Lab Manual',
        type: 'lab',
        description: 'Complete lab manual with experiments and procedures',
        fileSize: '2.8 MB',
        pages: 32,
        uploadDate: '18 Jan 2024',
        downloads: 210,
        views: 450,
        rating: 4.4,
        fileType: 'pdf',
        user: 'Lab Incharge'
      },
      {
        id: 6,
        title: 'Assignments',
        type: 'assignment',
        description: 'Solved assignments and practice problems',
        fileSize: '2.1 MB',
        pages: 25,
        uploadDate: '25 Jan 2024',
        downloads: 180,
        views: 420,
        rating: 4.3,
        fileType: 'doc',
        user: 'Teaching Assistant'
      }
    ];
    
    return { mockSubject, mockMaterials };
  }, [subjectId]);
  
  // Filter materials
  const filteredMaterials = useMemo(() => {
    let filtered = materials.filter(material => {
      const matchesType = selectedType === 'all' || material.type === selectedType;
      const matchesSearch = searchQuery === '' ||
        material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        material.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesType && matchesSearch;
    });
    
    // Sorting
    filtered.sort((a, b) => {
      let aValue, bValue;
      
      switch (sortBy) {
        case 'name':
          aValue = a.title.toLowerCase();
          bValue = b.title.toLowerCase();
          break;
        case 'downloads':
          aValue = a.downloads || 0;
          bValue = b.downloads || 0;
          break;
        case 'rating':
          aValue = a.rating || 0;
          bValue = b.rating || 0;
          break;
        case 'date':
        default:
          aValue = new Date(a.uploadDate);
          bValue = new Date(b.uploadDate);
      }
      
      return sortOrder === 'asc' ? aValue - bValue : bValue - aValue;
    });
    
    return filtered;
  }, [materials, selectedType, searchQuery, sortBy, sortOrder]);
  
  // Load data
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 800));
        const { mockSubject, mockMaterials } = generateMockData();
        setSubject(mockSubject);
        setMaterials(mockMaterials);
        
        // Load favorites/bookmarks from localStorage
        const savedFavorites = JSON.parse(localStorage.getItem(`favorites_${subjectId}`) || '[]');
        const savedBookmarks = JSON.parse(localStorage.getItem(`bookmarks_${subjectId}`) || '[]');
        setFavorites(new Set(savedFavorites));
        setBookmarks(new Set(savedBookmarks));
        
        showNotification('Success', 'Materials loaded successfully', 'success');
      } catch (error) {
        console.error('Error loading materials:', error);
        showNotification('Error', 'Failed to load materials', 'error');
      } finally {
        setLoading(false);
      }
    };
    
    loadData();
  }, [subjectId, generateMockData]);
  
  // Handle download
  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      // Simulate download
      await new Promise(resolve => setTimeout(resolve, 1500));
      
      // Create downloadable file
      const fileName = `${material.title.replace(/[^a-zA-Z0-9]/g, '_')}.${material.fileType || 'pdf'}`;
      const fileContent = `STUDY PORTAL\n\n${material.title}\n\nSubject: ${subject?.name}\nDescription: ${material.description}\n\nThis is a demo file for testing.\n\nDownloaded: ${new Date().toLocaleDateString()}`;
      
      const blob = new Blob([fileContent], { type: 'text/plain' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      
      // Update download count
      setMaterials(prev => prev.map(m => 
        m.id === material.id ? { ...m, downloads: (m.downloads || 0) + 1 } : m
      ));
      
      showNotification('Download Complete', `"${material.title}" downloaded successfully`, 'success');
    } catch (error) {
      console.error('Download error:', error);
      showNotification('Download Failed', 'Please try again', 'error');
    } finally {
      setDownloading(prev => ({ ...prev, [material.id]: false }));
    }
  };
  
  // Handle preview
  const handlePreview = (material) => {
    setPreviewMaterial(material);
  };
  
  // Handle favorite
  const handleFavorite = (materialId) => {
    const newFavorites = new Set(favorites);
    if (newFavorites.has(materialId)) {
      newFavorites.delete(materialId);
      showNotification('Removed', 'Removed from favorites', 'info');
    } else {
      newFavorites.add(materialId);
      showNotification('Added', 'Added to favorites', 'success');
    }
    setFavorites(newFavorites);
    localStorage.setItem(`favorites_${subjectId}`, JSON.stringify([...newFavorites]));
  };
  
  // Handle bookmark
  const handleBookmark = (materialId) => {
    const newBookmarks = new Set(bookmarks);
    if (newBookmarks.has(materialId)) {
      newBookmarks.delete(materialId);
      showNotification('Removed', 'Removed from bookmarks', 'info');
    } else {
      newBookmarks.add(materialId);
      showNotification('Added', 'Added to bookmarks', 'success');
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`bookmarks_${subjectId}`, JSON.stringify([...newBookmarks]));
  };
  
  // Handle select material
  const handleSelectMaterial = (materialId) => {
    const newSelection = new Set(selectedMaterials);
    if (newSelection.has(materialId)) {
      newSelection.delete(materialId);
    } else {
      newSelection.add(materialId);
    }
    setSelectedMaterials(newSelection);
  };
  
  // Handle select all
  const handleSelectAll = () => {
    if (selectedMaterials.size === filteredMaterials.length) {
      setSelectedMaterials(new Set());
    } else {
      setSelectedMaterials(new Set(filteredMaterials.map(m => m.id)));
    }
  };
  
  // Handle bulk download
  const handleBulkDownload = async () => {
    if (selectedMaterials.size === 0) {
      showNotification('No Selection', 'Select materials first', 'warning');
      return;
    }
    
    showNotification('Preparing', `Downloading ${selectedMaterials.size} files...`, 'info');
    
    for (const materialId of selectedMaterials) {
      const material = materials.find(m => m.id === materialId);
      if (material) {
        await handleDownload(material);
        await new Promise(resolve => setTimeout(resolve, 300));
      }
    }
    
    setSelectedMaterials(new Set());
    showNotification('Complete', 'All files downloaded', 'success');
  };
  
  // Handle share
  const handleShare = async (material) => {
    const shareData = {
      title: material.title,
      text: `Check out "${material.title}" on Study Portal`,
      url: window.location.href
    };
    
    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Share cancelled');
      }
    } else {
      navigator.clipboard.writeText(shareData.text + '\n' + shareData.url)
        .then(() => showNotification('Copied', 'Link copied to clipboard', 'success'))
        .catch(() => showNotification('Error', 'Failed to copy link', 'error'));
    }
  };
  
  // Calculate stats
  const stats = useMemo(() => ({
    total: materials.length,
    totalDownloads: materials.reduce((sum, m) => sum + (m.downloads || 0), 0),
    totalViews: materials.reduce((sum, m) => sum + (m.views || 0), 0),
    avgRating: materials.length > 0 
      ? (materials.reduce((sum, m) => sum + (m.rating || 0), 0) / materials.length).toFixed(1)
      : 0
  }), [materials]);
  
  // Loading state
  if (loading) {
    return (
      <div style={{
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)',
        padding: '20px',
        fontFamily: '"Segoe UI", sans-serif'
      }}>
        <button style={{
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          padding: '12px 24px',
          background: '#4f46e5',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer',
          fontWeight: '600',
          marginBottom: '30px'
        }} onClick={() => navigate(-1)}>
          <FaArrowLeft /> Back
        </button>
        <div style={{ textAlign: 'center', padding: '100px 20px' }}>
          <div style={{
            width: '50px',
            height: '50px',
            border: '5px solid #f3f4f6',
            borderTop: '5px solid #4f46e5',
            borderRadius: '50%',
            margin: '0 auto 20px',
            animation: 'spin 1s linear infinite'
          }}></div>
          <h3 style={{ color: '#6b7280' }}>Loading Materials...</h3>
        </div>
        <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }
  
  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)',
      padding: '20px',
      fontFamily: '"Segoe UI", sans-serif'
    }}>
      {/* Preview Modal */}
      {previewMaterial && (
        <PreviewModal
          material={previewMaterial}
          onClose={() => setPreviewMaterial(null)}
          onDownload={handleDownload}
        />
      )}
      
      <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
        
        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px', flexWrap: 'wrap', gap: '15px' }}>
          <button style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            padding: '12px 24px',
            background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
            color: 'white',
            border: 'none',
            borderRadius: '10px',
            cursor: 'pointer',
            fontWeight: '600',
            fontSize: '15px',
            boxShadow: '0 4px 12px rgba(79, 70, 229, 0.3)'
          }} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back to Subjects
          </button>
          
          {selectedMaterials.size > 0 && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px', background: 'white', padding: '12px 20px', borderRadius: '10px', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}>
              <span style={{ fontWeight: '600', color: '#4f46e5', background: '#f3f4f6', padding: '6px 12px', borderRadius: '20px', fontSize: '14px' }}>
                {selectedMaterials.size} selected
              </span>
              <button 
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  padding: '10px 20px',
                  background: 'linear-gradient(135deg, #10b981, #34d399)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontWeight: '600',
                  fontSize: '14px'
                }}
                onClick={handleBulkDownload}
              >
                <FaDownload /> Download Selected
              </button>
              <button 
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                  padding: '10px 16px',
                  background: '#f3f4f6',
                  color: '#6b7280',
                  border: '1px solid #e5e7eb',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontWeight: '500',
                  fontSize: '14px'
                }}
                onClick={() => setSelectedMaterials(new Set())}
              >
                <FaTimes /> Clear
              </button>
            </div>
          )}
        </div>
        
        {/* Subject Header */}
        <div style={{
          background: 'white',
          padding: '30px',
          borderRadius: '20px',
          marginBottom: '30px',
          boxShadow: '0 10px 30px rgba(0,0,0,0.08)',
          display: 'flex',
          alignItems: 'center',
          gap: '25px'
        }}>
          <div style={{
            width: '100px',
            height: '100px',
            borderRadius: '20px',
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            flexShrink: 0
          }}>
            <div style={{ fontSize: '48px', color: 'white' }}>📚</div>
          </div>
          
          <div style={{ flex: 1 }}>
            <h1 style={{ fontSize: '36px', fontWeight: '800', color: '#1f2937', marginBottom: '10px' }}>
              {subject?.name}
            </h1>
            <div style={{ display: 'flex', alignItems: 'center', gap: '20px', flexWrap: 'wrap', marginBottom: '15px' }}>
              <span style={{ display: 'flex', alignItems: 'center', gap: '6px', color: '#6b7280' }}>
                Code: <strong>{subject?.code}</strong>
              </span>
              <span style={{ display: 'flex', alignItems: 'center', gap: '6px', color: '#6b7280' }}>
                <FaStar /> <strong>{subject?.credits} Credits</strong>
              </span>
              <span style={{ display: 'flex', alignItems: 'center', gap: '6px', color: '#6b7280' }}>
                🏷️ <strong>{subject?.type}</strong>
              </span>
            </div>
            
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
              <span style={{ padding: '8px 16px', background: '#f3f4f6', borderRadius: '8px', color: '#6b7280', fontSize: '14px' }}>
                Course {courseId}
              </span>
              <FaChevronRight style={{ color: '#9ca3af', fontSize: '12px' }} />
              <span style={{ padding: '8px 16px', background: '#f3f4f6', borderRadius: '8px', color: '#6b7280', fontSize: '14px' }}>
                Year {yearId}
              </span>
              <FaChevronRight style={{ color: '#9ca3af', fontSize: '12px' }} />
              <span style={{ padding: '8px 16px', background: '#f3f4f6', borderRadius: '8px', color: '#6b7280', fontSize: '14px' }}>
                Semester {semId}
              </span>
              <FaChevronRight style={{ color: '#9ca3af', fontSize: '12px' }} />
              <span style={{ padding: '8px 16px', background: '#4f46e5', borderRadius: '8px', color: 'white', fontSize: '14px', fontWeight: '500' }}>
                {subject?.name}
              </span>
            </div>
          </div>
          
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '32px', fontWeight: '700', color: '#4f46e5' }}>{stats.total}</div>
            <div style={{ fontSize: '14px', color: '#6b7280' }}>Total Files</div>
          </div>
        </div>
        
        {/* Search and Filter */}
        <div style={{
          background: 'white',
          padding: '20px',
          borderRadius: '16px',
          marginBottom: '25px',
          boxShadow: '0 4px 12px rgba(0,0,0,0.05)'
        }}>
          <div style={{ position: 'relative', marginBottom: '20px' }}>
            <FaSearch style={{ position: 'absolute', left: '18px', top: '50%', transform: 'translateY(-50%)', color: '#9ca3af' }} />
            <input
              type="text"
              style={{
                width: '100%',
                padding: '16px 20px 16px 50px',
                fontSize: '16px',
                border: '2px solid #e5e7eb',
                borderRadius: '12px',
                background: '#f9fafb'
              }}
              placeholder="Search materials..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            {searchQuery && (
              <button 
                style={{
                  position: 'absolute',
                  right: '18px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: '#9ca3af',
                  cursor: 'pointer'
                }}
                onClick={() => setSearchQuery('')}
              >
                ×
              </button>
            )}
          </div>
          
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '15px' }}>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
              {MATERIAL_TYPES.map((type) => (
                <button
                  key={type.id}
                  style={{
                    padding: '12px 20px',
                    border: `2px solid ${selectedType === type.id ? type.color : '#e5e7eb'}`,
                    borderRadius: '8px',
                    background: selectedType === type.id ? type.color : 'white',
                    color: selectedType === type.id ? 'white' : '#4b5563',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px',
                    fontWeight: '500'
                  }}
                  onClick={() => setSelectedType(type.id)}
                >
                  {type.icon}
                  {type.name}
                  {type.id !== 'all' && (
                    <span style={{
                      background: selectedType === type.id ? 'rgba(255,255,255,0.2)' : '#f3f4f6',
                      color: selectedType === type.id ? 'white' : '#6b7280',
                      padding: '2px 8px',
                      borderRadius: '12px',
                      fontSize: '12px'
                    }}>
                      {materials.filter(m => m.type === type.id).length}
                    </span>
                  )}
                </button>
              ))}
            </div>
            
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <select 
                style={{ padding: '10px', border: '2px solid #e5e7eb', borderRadius: '8px' }}
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
              >
                <option value="date">Sort by Date</option>
                <option value="name">Sort by Name</option>
                <option value="downloads">Sort by Downloads</option>
              </select>
              <button 
                style={{ padding: '10px', background: '#f3f4f6', border: '2px solid #e5e7eb', borderRadius: '8px', cursor: 'pointer' }}
                onClick={() => setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc')}
              >
                {sortOrder === 'asc' ? <FaSortAmountUp /> : <FaSortAmountDown />}
              </button>
            </div>
          </div>
        </div>
        
        {/* Materials Grid */}
        {filteredMaterials.length === 0 ? (
          <div style={{
            background: 'white',
            padding: '60px 20px',
            borderRadius: '12px',
            textAlign: 'center',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ fontSize: '60px', marginBottom: '20px', opacity: '0.5' }}>📭</div>
            <h3 style={{ fontSize: '24px', fontWeight: '600', color: '#6b7280', marginBottom: '10px' }}>
              No materials found
            </h3>
            <p style={{ color: '#9ca3af', fontSize: '16px' }}>
              {searchQuery ? 'Try a different search' : 'No materials available'}
            </p>
          </div>
        ) : (
          <>
            <div style={{
              background: 'white',
              padding: '20px',
              borderRadius: '12px 12px 0 0',
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginBottom: '0'
            }}>
              <h3 style={{ fontSize: '20px', fontWeight: '600', color: '#1f2937' }}>
                {selectedType === 'all' ? 'All Materials' : MATERIAL_TYPE_MAP[selectedType]?.name}
                <span style={{ color: '#6b7280', marginLeft: '10px' }}>({filteredMaterials.length})</span>
              </h3>
              
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <input
                  type="checkbox"
                  id="selectAll"
                  checked={selectedMaterials.size === filteredMaterials.length}
                  onChange={handleSelectAll}
                  style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                />
                <label htmlFor="selectAll" style={{ cursor: 'pointer', color: '#6b7280' }}>
                  Select All
                </label>
              </div>
            </div>
            
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
              gap: '25px',
              padding: '25px',
              background: 'white',
              borderRadius: '0 0 12px 12px'
            }}>
              {filteredMaterials.map((material) => {
                const typeInfo = MATERIAL_TYPE_MAP[material.type];
                const fileIcon = getFileIcon(material.fileType);
                const isFavorite = favorites.has(material.id);
                const isBookmarked = bookmarks.has(material.id);
                const isSelected = selectedMaterials.has(material.id);
                
                return (
                  <div
                    key={material.id}
                    style={{
                      border: `2px solid ${isSelected ? '#4f46e5' : '#e5e7eb'}`,
                      borderRadius: '12px',
                      overflow: 'hidden',
                      background: 'white',
                      position: 'relative'
                    }}
                  >
                    {/* Selection Checkbox */}
                    <div style={{ position: 'absolute', top: '15px', left: '15px', zIndex: 10 }}>
                      <input
                        type="checkbox"
                        checked={isSelected}
                        onChange={() => handleSelectMaterial(material.id)}
                        style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                      />
                    </div>
                    
                    {/* Card Header */}
                    <div style={{
                      padding: '20px',
                      background: `${typeInfo.color}10`,
                      borderBottom: '1px solid #e5e7eb'
                    }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                          <span style={{ color: typeInfo.color }}>{typeInfo.icon}</span>
                          <span style={{ color: typeInfo.color, fontWeight: '600' }}>{typeInfo.name}</span>
                        </div>
                        <div style={{ display: 'flex', gap: '8px' }}>
                          {material.isNew && (
                            <span style={{ background: '#ef4444', color: 'white', padding: '4px 10px', borderRadius: '20px', fontSize: '11px' }}>
                              NEW
                            </span>
                          )}
                          <FileTypeBadge fileType={material.fileType} />
                        </div>
                      </div>
                    </div>
                    
                    {/* Card Content */}
                    <div style={{ padding: '20px' }}>
                      <h4 style={{ fontSize: '18px', fontWeight: '600', color: '#1f2937', marginBottom: '10px' }}>
                        {material.title}
                      </h4>
                      
                      <p style={{ color: '#6b7280', fontSize: '14px', marginBottom: '20px', minHeight: '60px' }}>
                        {material.description}
                      </p>
                      
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '20px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaClock /> {material.uploadDate}
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaDownload /> {material.downloads} downloads
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaEye /> {material.views} views
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaStar style={{ color: '#fbbf24' }} /> {material.rating}/5
                        </div>
                      </div>
                      
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: '#9ca3af', fontSize: '13px', paddingTop: '15px', borderTop: '1px solid #e5e7eb' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                          {fileIcon.icon} {material.fileSize}
                        </div>
                        <div>📖 {material.pages} pages</div>
                        <div>👤 {material.user}</div>
                      </div>
                    </div>
                    
                    {/* Action Buttons */}
                    <div style={{
                      padding: '20px',
                      background: '#f9fafb',
                      borderTop: '1px solid #e5e7eb',
                      display: 'flex',
                      justifyContent: 'space-between',
                      gap: '12px'
                    }}>
                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button
                          style={{
                            padding: '10px',
                            background: isFavorite ? '#fee2e2' : '#f3f4f6',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            color: isFavorite ? '#ef4444' : '#6b7280'
                          }}
                          onClick={() => handleFavorite(material.id)}
                        >
                          {isFavorite ? <FaHeart /> : <FaRegHeart />}
                        </button>
                        <button
                          style={{
                            padding: '10px',
                            background: isBookmarked ? '#fef3c7' : '#f3f4f6',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            color: isBookmarked ? '#d97706' : '#6b7280'
                          }}
                          onClick={() => handleBookmark(material.id)}
                        >
                          {isBookmarked ? <FaBookmark /> : <FaRegBookmark />}
                        </button>
                        <button
                          style={{
                            padding: '10px',
                            background: '#f3f4f6',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            color: '#6b7280'
                          }}
                          onClick={() => handleShare(material)}
                        >
                          <FaShareAlt />
                        </button>
                      </div>
                      
                      <div style={{ display: 'flex', gap: '12px' }}>
                        <button
                          style={{
                            padding: '10px 14px',
                            background: 'white',
                            border: '2px solid #e5e7eb',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '6px',
                            fontWeight: '600',
                            color: '#4b5563'
                          }}
                          onClick={() => handlePreview(material)}
                        >
                          <FaEye /> Preview
                        </button>
                        <button
                          style={{
                            padding: '10px 14px',
                            background: 'linear-gradient(135deg, #10b981, #34d399)',
                            color: 'white',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '6px',
                            fontWeight: '600',
                            minWidth: '120px',
                            justifyContent: 'center'
                          }}
                          onClick={() => handleDownload(material)}
                          disabled={downloading[material.id]}
                        >
                          {downloading[material.id] ? (
                            <>
                              <FaSpinner style={{ animation: 'spin 1s linear infinite' }} /> Downloading...
                            </>
                          ) : (
                            <>
                              <FaDownload /> Download
                            </>
                          )}
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default MaterialsPage;
